1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface QuoteStep {
6	  op: "quote";
7	  items: Array<Record<string, unknown>>;
8	}
9	
10	export interface ClaimStep {
11	  op: "claim";
12	  policy: number;
13	  incident: {
14	    cause: string;
15	    damages: Array<{ itemType: string; amount: number }>;
16	  };
17	}
18	
19	export type Step = QuoteStep | ClaimStep;
20	
21	export interface Scenario {
22	  customer: Customer;
23	  steps: Step[];
24	}
25	
26	export type StepResult =
27	  | { premium: number }
28	  | { payout: number; remainingCap: number };
29	
30	export interface ScenarioResult {
31	  results: StepResult[];
32	}
33	
34	const PROCESSING_FEE = 5;
35	
36	const BASE_PREMIUM: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	};
41	
42	const baseFor = (item: Record<string, unknown>): number =>
43	  BASE_PREMIUM[item.type as string] ?? 0;
44	
45	const quotePremium = (step: QuoteStep): StepResult => {
46	  const baseTotal = step.items.reduce((sum, item) => sum + baseFor(item), 0);
47	  const firstInsuranceSurcharge = baseTotal * 0.1;
48	  return { premium: baseTotal + firstInsuranceSurcharge + PROCESSING_FEE };
49	};
50	
51	const processStep = (step: Step): StepResult => {
52	  if (step.op === "quote") return quotePremium(step);
53	  return { payout: 0, remainingCap: 0 };
54	};
55	
56	export const runScenario = (scenario: Scenario): ScenarioResult => ({
57	  results: scenario.steps.map(processStep),
58	});
